class Solution {
public:
    int sumOfLeftLeaves(TreeNode* root) {
        if (!root) return 0;
        int s = 0;
        if (root->left && !root->left->left && !root->left->right)
            s += root->left->val;
        return s + sumOfLeftLeaves(root->left) + sumOfLeftLeaves(root->right);
    }
};

